                    lab = (i, j)

        dr = [0, 1, 0, -1]
        dc = [1, 0, -1, 0]

        # Count free neighbors for each cell
        free_neighbors = [[0]*m for _ in range(n)]
        for i in range(n):
            for j in range(m):
                if grid[i][j] == '#':
                    continue
                cnt = 0
                for d in range(4):
                    ni, nj = i+dr[d], j+dc[d]
                    if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#':
                        cnt += 1
                free_neighbors[i][j] = cnt

        forceable = [[False]*m for _ in range(n)]
        dq = deque()
        li, lj = lab
        forceable[li][lj] = True
        dq.append((li, lj))

        while dq:
            i, j = dq.popleft()
            for d in range(4):
                ni, nj = i+dr[d], j+dc[d]
                if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#' and not forceable[ni][nj]:
                    free_neighbors[ni][nj] -= 1
                    if free_neighbors[ni][nj] <= 1:
                        forceable[ni][nj] = True
                        dq.append((ni, nj))

        for i in range(n):
            for j in range(m):
                if grid[i][j] == '.' and forceable[i][j]:
                    grid[i][j] = '+'

        print('\n'.join(''.join(r) for r in grid))

solve()

